SELECT dbl_keyno
FROM sa_bill_log l
left join sa_bill_provider p
on l.dbl_provider_key = p.dbp_keyno
left join sa_bill_supplied s
on l.dbl_supplied_key = s.dbs_keyno
WHERE p.dbp_keyno = #{dbp_keyno}
and s.dbs_keyno = #{dbs_keyno}
and l.dbl_sub_keyno = #{dbl_sub_keyno}
and date_format(l.Conn_date , '%Y-%m') = date_format(now(), '%Y-%m')

mapper.insert:
INSERT INTO sa_bill_log ( dbl_provider_key, dbl_supplied_key, dbl_cash, dbl_scheck, dbl_draft, dbl_uncollected, dbl_chargetotal, dbl_taxtotal, dbl_grandtotal, dbl_subject, dbl_unit, dbl_quantity, dbl_unitprice, dbl_supplyprice, dbl_tax, dbl_description, dbl_p_name, dbl_s_name, dbl_purposetype, dbl_partytypecode, dbl_issueid, dbl_typecode1, dbl_typecode2, dbl_sub_description, dbl_issuedate, dbl_sub_issuedate, dbl_sub_keyno, dbl_si_hcnt, dbl_homeid, dbl_UI_KEYNO
)VALUES( #{dbp_keyno}, #{dbs_keyno}, #{cash}, #{scheck}, #{draft}, #{uncollected}, #{chargetotal}, #{taxtotal}, #{grandtotal}, #{subject}, #{unit}, #{quantity}, #{unitprice}, #{supplyprice}, #{tax}, #{description}, #{ir_companyname}, #{ie_companyname}, #{purposetype}, #{partytypecode}, #{issueid}, #{typecode1}, #{typecode2}, #{sub_description}, #{issuedate}, #{sub_issuedate}, #{dbl_sub_keyno}, #{si_hcnt}, #{homemunseo_id}, #{dbl_UI_KEYNO}
)

