	 		ORDER BY	dbl_grandtotal ${sortDirect}


	 		ORDER BY	dbl_issuedate ${sortDirect}


	 		ORDER BY	dbl_status ${sortDirect}


	 		ORDER BY 	COUNT DESC



		LIMIT  	#{recordCountPerPage} OFFSET #{firstIndex}

